PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE estat_metainfo (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  stats_data_id TEXT NOT NULL,           -- 統計表ID
  stat_name TEXT NOT NULL,               -- 統計名
  title TEXT NOT NULL,                   -- タイトル
  cat01 TEXT,                            -- カテゴリ1
  item_name TEXT,                        -- 項目名
  unit TEXT,                             -- 単位
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,  -- 更新日時
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP   -- 作成日時
);
CREATE TABLE ranking_visualizations (
  id INTEGER PRIMARY KEY AUTOINCREMENT,

  -- データ識別（複合キー）
  stats_data_id TEXT NOT NULL,         -- 統計表ID
  cat01 TEXT NOT NULL,                 -- カテゴリコード（estat_metainfoのcat01と対応）

  -- 地図可視化設定
  map_color_scheme TEXT DEFAULT 'interpolateBlues',
  map_diverging_midpoint TEXT DEFAULT 'zero',

  -- ランキング設定
  ranking_direction TEXT DEFAULT 'desc', -- 'asc', 'desc'

  -- 単位変換設定
  conversion_factor REAL DEFAULT 1,    -- 変換係数（元データ × 係数 = 表示値）
  decimal_places INTEGER DEFAULT 0,    -- 小数点以下桁数

  -- システム情報
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,

  -- 一意制約
  UNIQUE(stats_data_id, cat01)
);
CREATE TABLE choropleth_access_logs (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  subcategory_id TEXT,                        -- アクセスしたサブカテゴリ
  year TEXT,                                  -- 指定年度
  user_ip TEXT,                              -- ユーザーIP (匿名化)
  user_agent TEXT,                           -- ユーザーエージェント
  response_time_ms INTEGER,                   -- レスポンス時間 (ミリ秒)
  cache_hit BOOLEAN DEFAULT 0,               -- キャッシュヒットフラグ
  error_message TEXT,                         -- エラーメッセージ (エラー時)
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (subcategory_id) REFERENCES choropleth_subcategories(id) ON DELETE SET NULL
);
CREATE TABLE choropleth_user_settings (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  user_id INTEGER,                            -- ユーザーID (users テーブル参照)
  favorite_categories TEXT,                   -- お気に入りカテゴリ (JSON配列)
  favorite_subcategories TEXT,               -- お気に入りサブカテゴリ (JSON配列)
  default_color_scheme TEXT DEFAULT 'interpolateBlues', -- デフォルトカラースキーム
  default_year TEXT,                          -- デフォルト年度
  settings JSON,                              -- その他の設定 (JSON)
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
  UNIQUE(user_id)                             -- ユーザーごとに1レコード
);
CREATE TABLE subcategory_configs (
  id TEXT PRIMARY KEY,              -- 'land-area', 'land-use'
  category_id TEXT NOT NULL,        -- 'landweather'
  name TEXT NOT NULL,               -- '土地面積', '土地利用'
  description TEXT,
  default_ranking_key TEXT,         -- デフォルトの統計項目
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE ranking_items (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  subcategory_id TEXT NOT NULL,     -- 'land-area', 'land-use'
  ranking_key TEXT NOT NULL,        -- 'totalAreaExcluding'など
  label TEXT NOT NULL,              -- '総面積（除く）'
  stats_data_id TEXT NOT NULL,      -- '0000010102'
  cd_cat01 TEXT NOT NULL,           -- 'B1101'
  unit TEXT NOT NULL,               -- 'ha'
  name TEXT NOT NULL,               -- '総面積（北方地域及び竹島を除く）'
  display_order INTEGER DEFAULT 0,
  is_active BOOLEAN DEFAULT 1,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(subcategory_id, ranking_key)
);
CREATE TABLE estat_cache_metadata (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  
  -- キャッシュキー
  stats_data_id TEXT NOT NULL,
  category_code TEXT NOT NULL,
  time_code TEXT NOT NULL,
  
  -- メタデータ
  record_count INTEGER NOT NULL,           -- レコード数
  has_valid_values BOOLEAN DEFAULT 1,      -- 有効な値があるか
  
  -- キャッシュ管理
  cache_hit_count INTEGER DEFAULT 0,       -- キャッシュヒット回数
  last_accessed_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  
  -- タイムスタンプ
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  expires_at DATETIME,                     -- 有効期限
  
  -- ユニーク制約
  UNIQUE(stats_data_id, category_code, time_code)
);
CREATE TABLE estat_ranking_values (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  
  -- 統計データID（検索キー）
  stats_data_id TEXT NOT NULL,
  
  -- 外部キー（後方互換性のため保持）
  category_id INTEGER,
  time_period_id INTEGER,
  area_code TEXT NOT NULL,
  
  -- FormattedValueの全フィールド
  value TEXT NOT NULL,              -- 元の値（文字列）
  numeric_value REAL,               -- 数値（NULL許容）
  display_value TEXT,               -- 表示用の値
  rank INTEGER,                     -- ランキング順位
  
  -- 追加フィールド（FormattedValueの全情報）
  unit TEXT,                        -- 単位（例: "人", "円"）
  area_name TEXT,                   -- 都道府県名（例: "東京都", "大阪府"）
  category_code TEXT,               -- カテゴリコード（例: "A1101"）
  category_name TEXT,                -- カテゴリ名（例: "総人口"）
  time_code TEXT,                   -- 時間コード（例: "2024100000"）
  time_name TEXT,                   -- 時間名（例: "2024年10月"）
  
  -- メタデータ
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  
  -- ユニーク制約（重複データ防止）
  UNIQUE(stats_data_id, category_code, time_code, area_code)
);
CREATE TABLE users (
  id TEXT PRIMARY KEY,
  name TEXT,
  email TEXT UNIQUE NOT NULL,
  emailVerified DATETIME,
  image TEXT,
  username TEXT UNIQUE,
  password_hash TEXT,
  role TEXT DEFAULT 'user',
  is_active BOOLEAN DEFAULT 1,
  last_login DATETIME,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE accounts (
  id TEXT PRIMARY KEY,
  userId TEXT NOT NULL,
  type TEXT NOT NULL,
  provider TEXT NOT NULL,
  providerAccountId TEXT NOT NULL,
  refresh_token TEXT,
  access_token TEXT,
  expires_at INTEGER,
  token_type TEXT,
  scope TEXT,
  id_token TEXT,
  session_state TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (userId) REFERENCES users(id) ON DELETE CASCADE
);
CREATE TABLE sessions (
  id TEXT PRIMARY KEY,
  sessionToken TEXT UNIQUE NOT NULL,
  userId TEXT NOT NULL,
  expires DATETIME NOT NULL,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (userId) REFERENCES users(id) ON DELETE CASCADE
);
CREATE TABLE verification_tokens (
  identifier TEXT NOT NULL,
  token TEXT NOT NULL,
  expires DATETIME NOT NULL,
  PRIMARY KEY (identifier, token)
);
CREATE TABLE estat_data_history (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  stats_data_id TEXT NOT NULL,
  action TEXT NOT NULL,
  user_id TEXT,
  metadata_snapshot TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (user_id) REFERENCES users(id)
);
DELETE FROM sqlite_sequence;
CREATE INDEX idx_ranking_viz_stats_id ON ranking_visualizations(stats_data_id);
CREATE INDEX idx_ranking_viz_cat01 ON ranking_visualizations(cat01);
CREATE UNIQUE INDEX idx_ranking_viz_composite ON ranking_visualizations(stats_data_id, cat01);
CREATE INDEX idx_choropleth_access_logs_created_at ON choropleth_access_logs(created_at);
CREATE INDEX idx_choropleth_access_logs_subcategory_id ON choropleth_access_logs(subcategory_id);
CREATE INDEX idx_choropleth_access_logs_cache_hit ON choropleth_access_logs(cache_hit);
CREATE INDEX idx_choropleth_user_settings_user_id ON choropleth_user_settings(user_id);
CREATE INDEX idx_subcategory_configs_category ON subcategory_configs(category_id);
CREATE INDEX idx_ranking_items_subcategory ON ranking_items(subcategory_id);
CREATE INDEX idx_ranking_items_active ON ranking_items(is_active);
CREATE INDEX idx_ranking_items_display_order ON ranking_items(display_order);
CREATE UNIQUE INDEX idx_ranking_items_unique ON ranking_items(subcategory_id, ranking_key);
CREATE INDEX idx_estat_meta_lookup
  ON estat_cache_metadata(stats_data_id, category_code, time_code);
CREATE INDEX idx_estat_meta_expires
  ON estat_cache_metadata(expires_at);
CREATE INDEX idx_estat_val_lookup
  ON estat_ranking_values(stats_data_id, category_code, time_code);
CREATE INDEX idx_estat_val_category_code
  ON estat_ranking_values(category_code);
CREATE INDEX idx_estat_val_time_code
  ON estat_ranking_values(time_code);
CREATE INDEX idx_estat_val_area_code
  ON estat_ranking_values(area_code);
CREATE INDEX idx_estat_val_area_name
  ON estat_ranking_values(area_name);
CREATE INDEX idx_estat_val_rank
  ON estat_ranking_values(stats_data_id, category_code, time_code, rank);
CREATE INDEX idx_estat_val_composite
  ON estat_ranking_values(stats_data_id, category_code, time_code, area_code);
CREATE INDEX idx_estat_val_rank_covering
  ON estat_ranking_values(stats_data_id, category_code, time_code, rank, numeric_value);
CREATE INDEX idx_estat_val_stats_category_time
  ON estat_ranking_values(stats_data_id, category_code, time_code);
CREATE UNIQUE INDEX idx_accounts_provider ON accounts(provider, providerAccountId);
CREATE INDEX idx_sessions_userId ON sessions(userId);
CREATE INDEX idx_sessions_sessionToken ON sessions(sessionToken);
CREATE INDEX idx_users_username ON users(username);
CREATE INDEX idx_users_email ON users(email);
CREATE INDEX idx_history_stats_id ON estat_data_history(stats_data_id);
CREATE INDEX idx_history_user_id ON estat_data_history(user_id);
CREATE VIEW v_estat_summary AS
SELECT 
  stats_data_id,
  stat_name,
  title,
  COUNT(*) as item_count,
  MIN(created_at) as first_created,
  MAX(updated_at) as last_updated
FROM estat_metadata
GROUP BY stats_data_id, stat_name, title;
CREATE VIEW v_estat_metadata_summary AS
SELECT 
  stats_data_id,
  stat_name,
  title,
  COUNT(*) as item_count,
  MAX(updated_at) as last_updated
FROM estat_metadata 
GROUP BY stats_data_id, stat_name, title
ORDER BY last_updated DESC;
CREATE VIEW v_category_summary AS
SELECT 
  cat01 as category,
  COUNT(*) as count,
  COUNT(DISTINCT stats_data_id) as unique_stats_count
FROM estat_metadata 
WHERE cat01 IS NOT NULL
GROUP BY cat01 
ORDER BY count DESC;
CREATE VIEW v_user_activity AS
SELECT 
  u.username,
  u.email,
  u.last_login,
  COUNT(h.id) as action_count
FROM users u
LEFT JOIN estat_data_history h ON u.id = h.user_id
GROUP BY u.id, u.username, u.email, u.last_login
ORDER BY u.last_login DESC;
CREATE VIEW v_estat_metainfo_summary AS
SELECT 
  stats_data_id,
  stat_name,
  title,
  COUNT(*) as item_count,
  MAX(updated_at) as last_updated
FROM estat_metainfo 
GROUP BY stats_data_id, stat_name, title
ORDER BY last_updated DESC;
CREATE VIEW v_ranking_with_metadata AS
SELECT
  rv.*,
  m.stat_name,
  m.title,
  m.unit as original_unit,
  m.item_name
FROM ranking_visualizations rv
LEFT JOIN estat_metainfo m ON rv.stats_data_id = m.stats_data_id AND rv.cat01 = m.cat01;
CREATE VIEW v_choropleth_categories_full AS
SELECT
  c.id as category_id,
  c.name as category_name,
  c.description as category_description,
  c.icon as category_icon,
  c.color as category_color,
  c.display_order as category_display_order,
  s.id as subcategory_id,
  s.name as subcategory_name,
  s.description as subcategory_description,
  s.unit,
  s.data_type,
  s.stats_data_id,
  s.table_name,
  s.color_scheme,
  s.display_order as subcategory_display_order,
  s.last_updated,
  s.available_years
FROM choropleth_categories c
LEFT JOIN choropleth_subcategories s ON c.id = s.category_id
WHERE c.is_active = 1 AND (s.is_active = 1 OR s.is_active IS NULL)
ORDER BY c.display_order, s.display_order;
CREATE VIEW v_choropleth_cache_stats AS
SELECT
  subcategory_id,
  COUNT(*) as cache_count,
  SUM(access_count) as total_accesses,
  MAX(last_accessed_at) as last_access,
  AVG(CASE WHEN expires_at > datetime('now') THEN 1 ELSE 0 END) as cache_hit_rate,
  COUNT(CASE WHEN is_sample = 1 THEN 1 END) as sample_data_count
FROM choropleth_data_cache
GROUP BY subcategory_id;
CREATE VIEW v_choropleth_access_stats AS
SELECT
  DATE(created_at) as access_date,
  subcategory_id,
  COUNT(*) as access_count,
  AVG(response_time_ms) as avg_response_time,
  SUM(CASE WHEN cache_hit = 1 THEN 1 ELSE 0 END) as cache_hits,
  COUNT(CASE WHEN error_message IS NOT NULL THEN 1 END) as error_count
FROM choropleth_access_logs
GROUP BY DATE(created_at), subcategory_id
ORDER BY access_date DESC;
CREATE VIEW v_ranking_configs AS
SELECT 
  sc.id as subcategory_id,
  sc.category_id,
  sc.name as subcategory_name,
  sc.description,
  sc.default_ranking_key,
  ri.ranking_key,
  ri.label,
  ri.stats_data_id,
  ri.cd_cat01,
  ri.unit,
  ri.name as ranking_name,
  ri.display_order,
  ri.is_active,
  ri.created_at,
  ri.updated_at
FROM subcategory_configs sc
LEFT JOIN ranking_items ri ON sc.id = ri.subcategory_id AND ri.is_active = 1
ORDER BY sc.id, ri.display_order;
